request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?task ?taskName ?start ?startName ?end ?endName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .
  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL { ?task a bboExt:ChoreographyTask . ?task tai:belongsTo ?choreo . OPTIONAL { ?task bbo:name ?taskName . } }
  OPTIONAL { ?start a bboExt:StartEvent . ?start tai:belongsTo ?choreo . OPTIONAL { ?start bbo:name ?startName . } }
  OPTIONAL { ?end a bboExt:EndEvent . ?end tai:belongsTo ?choreo . OPTIONAL { ?end bbo:name ?endName . } }
}
LIMIT 50
